// G-TELP Level 2 모의고사 데이터 (80문항×20회)
const mockSets = [[{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"미래완료","q":"By next spring, the new training tower _____ construction.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by next spring → 미래완료(will have p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"The team refused _____ the building without proper equipment.","opts":["enter","entering","to enter","entered"],"ans":2,"exp":"refuse+to부정사","section":"문법"},{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"비교","q":"The new ladder truck is _____ the old one.","opts":["more efficient than","more efficient as","efficient than","efficient as"],"ans":0,"exp":"비교급: more+형용사+than","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did anyone get hurt at yesterday's call?\"\n\"One firefighter — minor burn on the left arm. He's back on duty.\"\n\nQ: 부상자 현황은?","opts":["부상 없음","소방관 1명 경상, 복귀","소방관 2명 부상","민간인 1명 부상"],"ans":1,"exp":"'One firefighter — minor burn ... back on duty'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the chief approve the new training budget?\"\n\"Partially — she approved the equipment portion but not the travel costs.\"\n\nQ: 승인된 예산 항목은?","opts":["전체 승인","장비 부분만 승인, 출장비 제외","전체 거부","출장비만 승인"],"ans":1,"exp":"'approved the equipment portion but not travel costs'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Will the structural engineer be on site during the search?\"\n\"Yes, she's already there assessing the load-bearing walls.\"\n\nQ: 구조 엔지니어의 현재 상황은?","opts":["아직 현장 도착 전","이미 내력벽 평가 중","원격으로 지원","취소됨"],"ans":1,"exp":"'already there assessing the load-bearing walls'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Should we request mutual aid?\"\n\"Not yet — let's see if the second unit can handle it.\"\n\nQ: 상호지원 요청 여부는?","opts":["즉시 요청","아직 보류","이미 요청","불필요"],"ans":1,"exp":"'Not yet — let's see if second unit can handle it'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the civilian evacuation complete before fire attack?\"\n\"All but two units on the seventh floor — they were evacuated during operations.\"\n\nQ: 화재 진압 전 대피 상황은?","opts":["전원 완료","7층 두 세대 제외 완료, 작전 중 대피","전원 미완료","대피 없이 진압 시작"],"ans":1,"exp":"'All but two units on the seventh floor'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Who submitted the after-action report?\"\n\"Sergeant Kim did — she filed it right after the debrief.\"\n\nQ: 보고서를 제출한 사람은?","opts":["지휘관","Kim 하사","훈련 코디네이터","부서장"],"ans":1,"exp":"'Sergeant Kim did'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"\"Primary search is conducted rapidly after fire attack begins, covering the most likely survival areas first. Secondary search is a thorough, systematic search of the entire structure after the fire is controlled.\"\n\nQ: 1차 수색과 2차 수색의 차이는?","opts":["수색 팀 수","빠른 주요 지역 vs 통제 후 체계적 전체 수색","밤낮 구분","장비 종류"],"ans":1,"exp":"'rapidly ... most likely survival areas' vs 'thorough, systematic ... after fire controlled'","passage":"J","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"}],[{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"준동사-to부정사","q":"The team refused _____ the building without proper equipment.","opts":["enter","entering","to enter","entered"],"ans":2,"exp":"refuse+to부정사","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"조동사-should","q":"She should _____ reported the malfunction immediately.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"준동사-동명사","q":"The chief avoided _____ the unstable section of the roof.","opts":["to enter","enter","entering","entered"],"ans":2,"exp":"avoid+동명사(V-ing)","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the generator at the training site working?\"\n\"It was fixed yesterday. Should be good to go.\"\n\nQ: 발전기 상태는?","opts":["고장 중","어제 수리 완료, 사용 가능","교체 예정","점검 중"],"ans":1,"exp":"'fixed yesterday. Should be good to go'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Has the MAYDAY been called off?\"\n\"Confirmed — the missing firefighter was found on the second floor landing.\"\n\nQ: MAYDAY 해제 이유는?","opts":["화재 진압 완료","실종 소방관 2층 계단참에서 발견","대원 전원 탈출 확인","건물 붕괴 위험 해소"],"ans":1,"exp":"'missing firefighter was found on second floor landing'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"When's the next shift change?\"\n\"0800 tomorrow. The night crew is running a drill at 0600 before handover.\"\n\nQ: 야간 팀의 훈련 시간은?","opts":["0600","0700","0800","0900"],"ans":0,"exp":"'drill at 0600 before handover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How far out is the hazmat team?\"\n\"ETA fifteen minutes. Establish the hot zone and hold until they arrive.\"\n\nQ: 현재 지시사항은?","opts":["즉시 진입","위험 구역 설정 후 HAZMAT 팀 도착까지 대기","철수","민간인 대피 실시"],"ans":1,"exp":"'Establish hot zone and hold until they arrive'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the water supply hold during the warehouse fire?\"\n\"We had to switch to the secondary hydrant on Oak Street halfway through.\"\n\nQ: 작전 중 어떤 문제가 발생했는가?","opts":["물 공급 완전 차단","중간에 보조 소화전으로 전환 필요","펌프 고장","호스 파열"],"ans":1,"exp":"'switch to secondary hydrant on Oak Street halfway through'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Will the structural engineer be on site during the search?\"\n\"Yes, she's already there assessing the load-bearing walls.\"\n\nQ: 구조 엔지니어의 현재 상황은?","opts":["아직 현장 도착 전","이미 내력벽 평가 중","원격으로 지원","취소됨"],"ans":1,"exp":"'already there assessing the load-bearing walls'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"미래완료","q":"By next spring, the new training tower _____ construction.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by next spring → 미래완료(will have p.p.)","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the protocol, the accident would not have happened.","opts":["followed","follows","had followed","has followed"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"과거완료","q":"The injured firefighter _____ already been transported when backup arrived.","opts":["has","had","is","was"],"ans":1,"exp":"when+과거 이전 완료 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"현재완료","q":"They _____ already submitted the incident report.","opts":["have","had","are","were"],"ans":0,"exp":"already → 현재완료(have p.p.)","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Who submitted the after-action report?\"\n\"Sergeant Kim did — she filed it right after the debrief.\"\n\nQ: 보고서를 제출한 사람은?","opts":["지휘관","Kim 하사","훈련 코디네이터","부서장"],"ans":1,"exp":"'Sergeant Kim did'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the engine back from maintenance?\"\n\"Not yet — they said it'll be ready by end of shift.\"\n\nQ: 엔진의 현재 상태는?","opts":["정비 완료","아직 정비 중, 교대 종료 전 완료 예정","정비 취소됨","새 장비로 교체됨"],"ans":1,"exp":"'Not yet ... ready by end of shift' → 아직 정비 중","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Has the MAYDAY been called off?\"\n\"Confirmed — the missing firefighter was found on the second floor landing.\"\n\nQ: MAYDAY 해제 이유는?","opts":["화재 진압 완료","실종 소방관 2층 계단참에서 발견","대원 전원 탈출 확인","건물 붕괴 위험 해소"],"ans":1,"exp":"'missing firefighter was found on second floor landing'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How many units responded to the apartment fire?\"\n\"Five engines, two ladders, and one rescue.\"\n\nQ: 출동한 사다리차 수는?","opts":["1대","2대","3대","5대"],"ans":1,"exp":"'two ladders'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did anyone get hurt at yesterday's call?\"\n\"One firefighter — minor burn on the left arm. He's back on duty.\"\n\nQ: 부상자 현황은?","opts":["부상 없음","소방관 1명 경상, 복귀","소방관 2명 부상","민간인 1명 부상"],"ans":1,"exp":"'One firefighter — minor burn ... back on duty'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Should we request mutual aid?\"\n\"Not yet — let's see if the second unit can handle it.\"\n\nQ: 상호지원 요청 여부는?","opts":["즉시 요청","아직 보류","이미 요청","불필요"],"ans":1,"exp":"'Not yet — let's see if second unit can handle it'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the ladder truck available for the afternoon drill?\"\n\"It just came back from its annual inspection. Should be good.\"\n\nQ: 사다리차 상태는?","opts":["수리 중","연간 점검 복귀, 사용 가능","다른 현장 출동 중","예약됨"],"ans":1,"exp":"'just came back from annual inspection'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"관계사-where","q":"The station _____ he trained for ten years is being renovated.","opts":["where","which","that","who"],"ans":0,"exp":"장소 선행사+부사 역할 → where","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"준동사-동명사","q":"The chief avoided _____ the unstable section of the roof.","opts":["to enter","enter","entering","entered"],"ans":2,"exp":"avoid+동명사(V-ing)","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"관계사-which","q":"The building, _____ had been abandoned for years, was finally demolished.","opts":["who","which","whose","whom"],"ans":1,"exp":"콤마+사물 선행사 → 계속적 용법 which","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"비교","q":"The new ladder truck is _____ the old one.","opts":["more efficient than","more efficient as","efficient than","efficient as"],"ans":0,"exp":"비교급: more+형용사+than","section":"문법"},{"type":"준동사-동명사","q":"She denied _____ the safety log before the inspection.","opts":["to falsify","falsify","falsifying","falsified"],"ans":2,"exp":"deny+동명사(V-ing)","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"The team refused _____ the building without proper equipment.","opts":["enter","entering","to enter","entered"],"ans":2,"exp":"refuse+to부정사","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"현재완료","q":"They _____ already submitted the incident report.","opts":["have","had","are","were"],"ans":0,"exp":"already → 현재완료(have p.p.)","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Who submitted the after-action report?\"\n\"Sergeant Kim did — she filed it right after the debrief.\"\n\nQ: 보고서를 제출한 사람은?","opts":["지휘관","Kim 하사","훈련 코디네이터","부서장"],"ans":1,"exp":"'Sergeant Kim did'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did anyone get hurt at yesterday's call?\"\n\"One firefighter — minor burn on the left arm. He's back on duty.\"\n\nQ: 부상자 현황은?","opts":["부상 없음","소방관 1명 경상, 복귀","소방관 2명 부상","민간인 1명 부상"],"ans":1,"exp":"'One firefighter — minor burn ... back on duty'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the breathing apparatus bay restocked?\"\n\"Just finished — all 12 units are charged and ready.\"\n\nQ: 공기호흡기 보충 현황은?","opts":["미완료","12개 전부 충전 완료","일부만 완료","순서 대기 중"],"ans":1,"exp":"'all 12 units are charged and ready'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Are there enough SCBA units for both crews?\"\n\"Barely — we have eight, and we need ten.\"\n\nQ: SCBA 장비 현황은?","opts":["충분","2개 부족","충분히 남음","전혀 없음"],"ans":1,"exp":"'eight, and we need ten' → 2개 부족","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is Captain Yoon leading the debrief today?\"\n\"No, she's at headquarters. Lieutenant Cha will cover.\"\n\nQ: 오늘 디브리핑을 이끄는 사람은?","opts":["Yoon 대위","Cha 중위","본부 직원","훈련 코디네이터"],"ans":1,"exp":"'Lieutenant Cha will cover'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"}],[{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"미래완료","q":"By next spring, the new training tower _____ construction.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by next spring → 미래완료(will have p.p.)","section":"문법"},{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"과거완료","q":"The injured firefighter _____ already been transported when backup arrived.","opts":["has","had","is","was"],"ans":1,"exp":"when+과거 이전 완료 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"type":"현재완료","q":"We _____ not yet received confirmation from headquarters.","opts":["have","had","are","were"],"ans":0,"exp":"yet → 현재완료 부정문","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Will the structural engineer be on site during the search?\"\n\"Yes, she's already there assessing the load-bearing walls.\"\n\nQ: 구조 엔지니어의 현재 상황은?","opts":["아직 현장 도착 전","이미 내력벽 평가 중","원격으로 지원","취소됨"],"ans":1,"exp":"'already there assessing the load-bearing walls'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"When does the new hose evolution training start?\"\n\"Next Tuesday. Attendance is mandatory for all engine crews.\"\n\nQ: 교육의 특이사항은?","opts":["자율 참석","엔진 팀 전원 의무 참석","특정 팀만 해당","온라인 진행"],"ans":1,"exp":"'mandatory for all engine crews'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the breathing apparatus bay restocked?\"\n\"Just finished — all 12 units are charged and ready.\"\n\nQ: 공기호흡기 보충 현황은?","opts":["미완료","12개 전부 충전 완료","일부만 완료","순서 대기 중"],"ans":1,"exp":"'all 12 units are charged and ready'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"The victim was found on the third floor?\"\n\"Second. The third floor was already fully involved.\"\n\nQ: 피해자가 발견된 층은?","opts":["1층","2층","3층","4층"],"ans":1,"exp":"'Second' → 2층","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Who submitted the after-action report?\"\n\"Sergeant Kim did — she filed it right after the debrief.\"\n\nQ: 보고서를 제출한 사람은?","opts":["지휘관","Kim 하사","훈련 코디네이터","부서장"],"ans":1,"exp":"'Sergeant Kim did'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How many units responded to the apartment fire?\"\n\"Five engines, two ladders, and one rescue.\"\n\nQ: 출동한 사다리차 수는?","opts":["1대","2대","3대","5대"],"ans":1,"exp":"'two ladders'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"}],[{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"조동사-should","q":"She should _____ reported the malfunction immediately.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"관계사-which","q":"The building, _____ had been abandoned for years, was finally demolished.","opts":["who","which","whose","whom"],"ans":1,"exp":"콤마+사물 선행사 → 계속적 용법 which","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"조동사-ought","q":"The team ought _____ established a command post first.","opts":["have","to have","having","to having"],"ans":1,"exp":"ought to have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"준동사-동명사","q":"The recruits enjoy _____ in the fitness facility after training.","opts":["to work out","work out","working out","worked out"],"ans":2,"exp":"enjoy+동명사(V-ing)","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"The victim was found on the third floor?\"\n\"Second. The third floor was already fully involved.\"\n\nQ: 피해자가 발견된 층은?","opts":["1층","2층","3층","4층"],"ans":1,"exp":"'Second' → 2층","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the engine back from maintenance?\"\n\"Not yet — they said it'll be ready by end of shift.\"\n\nQ: 엔진의 현재 상태는?","opts":["정비 완료","아직 정비 중, 교대 종료 전 완료 예정","정비 취소됨","새 장비로 교체됨"],"ans":1,"exp":"'Not yet ... ready by end of shift' → 아직 정비 중","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Will the structural engineer be on site during the search?\"\n\"Yes, she's already there assessing the load-bearing walls.\"\n\nQ: 구조 엔지니어의 현재 상황은?","opts":["아직 현장 도착 전","이미 내력벽 평가 중","원격으로 지원","취소됨"],"ans":1,"exp":"'already there assessing the load-bearing walls'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the breathing apparatus bay restocked?\"\n\"Just finished — all 12 units are charged and ready.\"\n\nQ: 공기호흡기 보충 현황은?","opts":["미완료","12개 전부 충전 완료","일부만 완료","순서 대기 중"],"ans":1,"exp":"'all 12 units are charged and ready'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Should we request mutual aid?\"\n\"Not yet — let's see if the second unit can handle it.\"\n\nQ: 상호지원 요청 여부는?","opts":["즉시 요청","아직 보류","이미 요청","불필요"],"ans":1,"exp":"'Not yet — let's see if second unit can handle it'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How many units responded to the apartment fire?\"\n\"Five engines, two ladders, and one rescue.\"\n\nQ: 출동한 사다리차 수는?","opts":["1대","2대","3대","5대"],"ans":1,"exp":"'two ladders'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Primary search is conducted rapidly after fire attack begins, covering the most likely survival areas first. Secondary search is a thorough, systematic search of the entire structure after the fire is controlled.\"\n\nQ: 1차 수색과 2차 수색의 차이는?","opts":["수색 팀 수","빠른 주요 지역 vs 통제 후 체계적 전체 수색","밤낮 구분","장비 종류"],"ans":1,"exp":"'rapidly ... most likely survival areas' vs 'thorough, systematic ... after fire controlled'","passage":"J","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"}],[{"type":"현재완료","q":"They _____ already submitted the incident report.","opts":["have","had","are","were"],"ans":0,"exp":"already → 현재완료(have p.p.)","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"조동사-needn't","q":"You needn't _____ brought extra hose — there was enough on site.","opts":["have","had","to have","to had"],"ans":0,"exp":"needn't have p.p. = 할 필요가 없었는데 했다","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"type":"준동사-to부정사","q":"The team refused _____ the building without proper equipment.","opts":["enter","entering","to enter","entered"],"ans":2,"exp":"refuse+to부정사","section":"문법"},{"type":"관계사-which","q":"The building, _____ had been abandoned for years, was finally demolished.","opts":["who","which","whose","whom"],"ans":1,"exp":"콤마+사물 선행사 → 계속적 용법 which","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the protocol, the accident would not have happened.","opts":["followed","follows","had followed","has followed"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How long was the response time?\"\n\"Four minutes, twelve seconds — a new record for this district.\"\n\nQ: 대응 시간은?","opts":["3분 12초","4분 12초","5분 12초","6분 12초"],"ans":1,"exp":"'Four minutes, twelve seconds'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the new accountability system active yet?\"\n\"It went live this morning. Everyone needs to register by noon.\"\n\nQ: 새 시스템의 등록 마감 시간은?","opts":["오전 9시","정오","오후 3시","오늘 자정"],"ans":1,"exp":"'register by noon'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the water supply hold during the warehouse fire?\"\n\"We had to switch to the secondary hydrant on Oak Street halfway through.\"\n\nQ: 작전 중 어떤 문제가 발생했는가?","opts":["물 공급 완전 차단","중간에 보조 소화전으로 전환 필요","펌프 고장","호스 파열"],"ans":1,"exp":"'switch to secondary hydrant on Oak Street halfway through'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the engine back from maintenance?\"\n\"Not yet — they said it'll be ready by end of shift.\"\n\nQ: 엔진의 현재 상태는?","opts":["정비 완료","아직 정비 중, 교대 종료 전 완료 예정","정비 취소됨","새 장비로 교체됨"],"ans":1,"exp":"'Not yet ... ready by end of shift' → 아직 정비 중","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did they find the point of origin?\"\n\"Preliminary investigation points to an overloaded outlet in the utility room.\"\n\nQ: 추정 화재 원인은?","opts":["방화","다용도실 과부하 콘센트","가스 누출","담배꽁초"],"ans":1,"exp":"'overloaded outlet in the utility room'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the chief approve the new training budget?\"\n\"Partially — she approved the equipment portion but not the travel costs.\"\n\nQ: 승인된 예산 항목은?","opts":["전체 승인","장비 부분만 승인, 출장비 제외","전체 거부","출장비만 승인"],"ans":1,"exp":"'approved the equipment portion but not travel costs'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How far out is the hazmat team?\"\n\"ETA fifteen minutes. Establish the hot zone and hold until they arrive.\"\n\nQ: 현재 지시사항은?","opts":["즉시 진입","위험 구역 설정 후 HAZMAT 팀 도착까지 대기","철수","민간인 대피 실시"],"ans":1,"exp":"'Establish hot zone and hold until they arrive'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"}],[{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"과거완료","q":"The injured firefighter _____ already been transported when backup arrived.","opts":["has","had","is","was"],"ans":1,"exp":"when+과거 이전 완료 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"관계사-who","q":"The firefighter _____ saved the child received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"관계사-which","q":"The building, _____ had been abandoned for years, was finally demolished.","opts":["who","which","whose","whom"],"ans":1,"exp":"콤마+사물 선행사 → 계속적 용법 which","section":"문법"},{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"현재완료","q":"We _____ not yet received confirmation from headquarters.","opts":["have","had","are","were"],"ans":0,"exp":"yet → 현재완료 부정문","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"준동사-동명사","q":"She denied _____ the safety log before the inspection.","opts":["to falsify","falsify","falsifying","falsified"],"ans":2,"exp":"deny+동명사(V-ing)","section":"문법"},{"type":"관계사-where","q":"The station _____ he trained for ten years is being renovated.","opts":["where","which","that","who"],"ans":0,"exp":"장소 선행사+부사 역할 → where","section":"문법"},{"type":"준동사-to부정사","q":"The team refused _____ the building without proper equipment.","opts":["enter","entering","to enter","entered"],"ans":2,"exp":"refuse+to부정사","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the water supply hold during the warehouse fire?\"\n\"We had to switch to the secondary hydrant on Oak Street halfway through.\"\n\nQ: 작전 중 어떤 문제가 발생했는가?","opts":["물 공급 완전 차단","중간에 보조 소화전으로 전환 필요","펌프 고장","호스 파열"],"ans":1,"exp":"'switch to secondary hydrant on Oak Street halfway through'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"The victim was found on the third floor?\"\n\"Second. The third floor was already fully involved.\"\n\nQ: 피해자가 발견된 층은?","opts":["1층","2층","3층","4층"],"ans":1,"exp":"'Second' → 2층","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How far out is the hazmat team?\"\n\"ETA fifteen minutes. Establish the hot zone and hold until they arrive.\"\n\nQ: 현재 지시사항은?","opts":["즉시 진입","위험 구역 설정 후 HAZMAT 팀 도착까지 대기","철수","민간인 대피 실시"],"ans":1,"exp":"'Establish hot zone and hold until they arrive'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the generator at the training site working?\"\n\"It was fixed yesterday. Should be good to go.\"\n\nQ: 발전기 상태는?","opts":["고장 중","어제 수리 완료, 사용 가능","교체 예정","점검 중"],"ans":1,"exp":"'fixed yesterday. Should be good to go'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the chief approve the new training budget?\"\n\"Partially — she approved the equipment portion but not the travel costs.\"\n\nQ: 승인된 예산 항목은?","opts":["전체 승인","장비 부분만 승인, 출장비 제외","전체 거부","출장비만 승인"],"ans":1,"exp":"'approved the equipment portion but not travel costs'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"}],[{"type":"준동사-to부정사","q":"The team refused _____ the building without proper equipment.","opts":["enter","entering","to enter","entered"],"ans":2,"exp":"refuse+to부정사","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"준동사-동명사","q":"The recruits enjoy _____ in the fitness facility after training.","opts":["to work out","work out","working out","worked out"],"ans":2,"exp":"enjoy+동명사(V-ing)","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"관계사-who","q":"The firefighter _____ saved the child received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"관계사-where","q":"The station _____ he trained for ten years is being renovated.","opts":["where","which","that","who"],"ans":0,"exp":"장소 선행사+부사 역할 → where","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"조동사-ought","q":"The team ought _____ established a command post first.","opts":["have","to have","having","to having"],"ans":1,"exp":"ought to have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the protocol, the accident would not have happened.","opts":["followed","follows","had followed","has followed"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"준동사-동명사","q":"The chief avoided _____ the unstable section of the roof.","opts":["to enter","enter","entering","entered"],"ans":2,"exp":"avoid+동명사(V-ing)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"When does the new hose evolution training start?\"\n\"Next Tuesday. Attendance is mandatory for all engine crews.\"\n\nQ: 교육의 특이사항은?","opts":["자율 참석","엔진 팀 전원 의무 참석","특정 팀만 해당","온라인 진행"],"ans":1,"exp":"'mandatory for all engine crews'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Should we request mutual aid?\"\n\"Not yet — let's see if the second unit can handle it.\"\n\nQ: 상호지원 요청 여부는?","opts":["즉시 요청","아직 보류","이미 요청","불필요"],"ans":1,"exp":"'Not yet — let's see if second unit can handle it'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"The victim was found on the third floor?\"\n\"Second. The third floor was already fully involved.\"\n\nQ: 피해자가 발견된 층은?","opts":["1층","2층","3층","4층"],"ans":1,"exp":"'Second' → 2층","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the civilian evacuation complete before fire attack?\"\n\"All but two units on the seventh floor — they were evacuated during operations.\"\n\nQ: 화재 진압 전 대피 상황은?","opts":["전원 완료","7층 두 세대 제외 완료, 작전 중 대피","전원 미완료","대피 없이 진압 시작"],"ans":1,"exp":"'All but two units on the seventh floor'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How far out is the hazmat team?\"\n\"ETA fifteen minutes. Establish the hot zone and hold until they arrive.\"\n\nQ: 현재 지시사항은?","opts":["즉시 진입","위험 구역 설정 후 HAZMAT 팀 도착까지 대기","철수","민간인 대피 실시"],"ans":1,"exp":"'Establish hot zone and hold until they arrive'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the breathing apparatus bay restocked?\"\n\"Just finished — all 12 units are charged and ready.\"\n\nQ: 공기호흡기 보충 현황은?","opts":["미완료","12개 전부 충전 완료","일부만 완료","순서 대기 중"],"ans":1,"exp":"'all 12 units are charged and ready'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the new accountability system active yet?\"\n\"It went live this morning. Everyone needs to register by noon.\"\n\nQ: 새 시스템의 등록 마감 시간은?","opts":["오전 9시","정오","오후 3시","오늘 자정"],"ans":1,"exp":"'register by noon'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"}],[{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"관계사-who","q":"The firefighter _____ saved the child received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"과거완료","q":"The injured firefighter _____ already been transported when backup arrived.","opts":["has","had","is","was"],"ans":1,"exp":"when+과거 이전 완료 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"미래완료","q":"By next spring, the new training tower _____ construction.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by next spring → 미래완료(will have p.p.)","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"조동사-ought","q":"The team ought _____ established a command post first.","opts":["have","to have","having","to having"],"ans":1,"exp":"ought to have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"현재완료","q":"They _____ already submitted the incident report.","opts":["have","had","are","were"],"ans":0,"exp":"already → 현재완료(have p.p.)","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the chief approve the new training budget?\"\n\"Partially — she approved the equipment portion but not the travel costs.\"\n\nQ: 승인된 예산 항목은?","opts":["전체 승인","장비 부분만 승인, 출장비 제외","전체 거부","출장비만 승인"],"ans":1,"exp":"'approved the equipment portion but not travel costs'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the engine back from maintenance?\"\n\"Not yet — they said it'll be ready by end of shift.\"\n\nQ: 엔진의 현재 상태는?","opts":["정비 완료","아직 정비 중, 교대 종료 전 완료 예정","정비 취소됨","새 장비로 교체됨"],"ans":1,"exp":"'Not yet ... ready by end of shift' → 아직 정비 중","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"When's the next shift change?\"\n\"0800 tomorrow. The night crew is running a drill at 0600 before handover.\"\n\nQ: 야간 팀의 훈련 시간은?","opts":["0600","0700","0800","0900"],"ans":0,"exp":"'drill at 0600 before handover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Has the MAYDAY been called off?\"\n\"Confirmed — the missing firefighter was found on the second floor landing.\"\n\nQ: MAYDAY 해제 이유는?","opts":["화재 진압 완료","실종 소방관 2층 계단참에서 발견","대원 전원 탈출 확인","건물 붕괴 위험 해소"],"ans":1,"exp":"'missing firefighter was found on second floor landing'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Are there enough SCBA units for both crews?\"\n\"Barely — we have eight, and we need ten.\"\n\nQ: SCBA 장비 현황은?","opts":["충분","2개 부족","충분히 남음","전혀 없음"],"ans":1,"exp":"'eight, and we need ten' → 2개 부족","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"\"Primary search is conducted rapidly after fire attack begins, covering the most likely survival areas first. Secondary search is a thorough, systematic search of the entire structure after the fire is controlled.\"\n\nQ: 1차 수색과 2차 수색의 차이는?","opts":["수색 팀 수","빠른 주요 지역 vs 통제 후 체계적 전체 수색","밤낮 구분","장비 종류"],"ans":1,"exp":"'rapidly ... most likely survival areas' vs 'thorough, systematic ... after fire controlled'","passage":"J","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"}],[{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"비교","q":"The new ladder truck is _____ the old one.","opts":["more efficient than","more efficient as","efficient than","efficient as"],"ans":0,"exp":"비교급: more+형용사+than","section":"문법"},{"type":"관계사-who","q":"The firefighter _____ saved the child received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"현재완료","q":"They _____ already submitted the incident report.","opts":["have","had","are","were"],"ans":0,"exp":"already → 현재완료(have p.p.)","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"조동사-ought","q":"The team ought _____ established a command post first.","opts":["have","to have","having","to having"],"ans":1,"exp":"ought to have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the engine back from maintenance?\"\n\"Not yet — they said it'll be ready by end of shift.\"\n\nQ: 엔진의 현재 상태는?","opts":["정비 완료","아직 정비 중, 교대 종료 전 완료 예정","정비 취소됨","새 장비로 교체됨"],"ans":1,"exp":"'Not yet ... ready by end of shift' → 아직 정비 중","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the civilian evacuation complete before fire attack?\"\n\"All but two units on the seventh floor — they were evacuated during operations.\"\n\nQ: 화재 진압 전 대피 상황은?","opts":["전원 완료","7층 두 세대 제외 완료, 작전 중 대피","전원 미완료","대피 없이 진압 시작"],"ans":1,"exp":"'All but two units on the seventh floor'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the chief approve the new training budget?\"\n\"Partially — she approved the equipment portion but not the travel costs.\"\n\nQ: 승인된 예산 항목은?","opts":["전체 승인","장비 부분만 승인, 출장비 제외","전체 거부","출장비만 승인"],"ans":1,"exp":"'approved the equipment portion but not travel costs'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Who submitted the after-action report?\"\n\"Sergeant Kim did — she filed it right after the debrief.\"\n\nQ: 보고서를 제출한 사람은?","opts":["지휘관","Kim 하사","훈련 코디네이터","부서장"],"ans":1,"exp":"'Sergeant Kim did'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Are there enough SCBA units for both crews?\"\n\"Barely — we have eight, and we need ten.\"\n\nQ: SCBA 장비 현황은?","opts":["충분","2개 부족","충분히 남음","전혀 없음"],"ans":1,"exp":"'eight, and we need ten' → 2개 부족","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did they find the point of origin?\"\n\"Preliminary investigation points to an overloaded outlet in the utility room.\"\n\nQ: 추정 화재 원인은?","opts":["방화","다용도실 과부하 콘센트","가스 누출","담배꽁초"],"ans":1,"exp":"'overloaded outlet in the utility room'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"조동사-should","q":"She should _____ reported the malfunction immediately.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"현재완료","q":"They _____ already submitted the incident report.","opts":["have","had","are","were"],"ans":0,"exp":"already → 현재완료(have p.p.)","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"준동사-동명사","q":"The chief avoided _____ the unstable section of the roof.","opts":["to enter","enter","entering","entered"],"ans":2,"exp":"avoid+동명사(V-ing)","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"type":"준동사-to부정사","q":"The team refused _____ the building without proper equipment.","opts":["enter","entering","to enter","entered"],"ans":2,"exp":"refuse+to부정사","section":"문법"},{"type":"관계사-who","q":"The firefighter _____ saved the child received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the civilian evacuation complete before fire attack?\"\n\"All but two units on the seventh floor — they were evacuated during operations.\"\n\nQ: 화재 진압 전 대피 상황은?","opts":["전원 완료","7층 두 세대 제외 완료, 작전 중 대피","전원 미완료","대피 없이 진압 시작"],"ans":1,"exp":"'All but two units on the seventh floor'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the new accountability system active yet?\"\n\"It went live this morning. Everyone needs to register by noon.\"\n\nQ: 새 시스템의 등록 마감 시간은?","opts":["오전 9시","정오","오후 3시","오늘 자정"],"ans":1,"exp":"'register by noon'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is Captain Yoon leading the debrief today?\"\n\"No, she's at headquarters. Lieutenant Cha will cover.\"\n\nQ: 오늘 디브리핑을 이끄는 사람은?","opts":["Yoon 대위","Cha 중위","본부 직원","훈련 코디네이터"],"ans":1,"exp":"'Lieutenant Cha will cover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the engine back from maintenance?\"\n\"Not yet — they said it'll be ready by end of shift.\"\n\nQ: 엔진의 현재 상태는?","opts":["정비 완료","아직 정비 중, 교대 종료 전 완료 예정","정비 취소됨","새 장비로 교체됨"],"ans":1,"exp":"'Not yet ... ready by end of shift' → 아직 정비 중","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"\"Primary search is conducted rapidly after fire attack begins, covering the most likely survival areas first. Secondary search is a thorough, systematic search of the entire structure after the fire is controlled.\"\n\nQ: 1차 수색과 2차 수색의 차이는?","opts":["수색 팀 수","빠른 주요 지역 vs 통제 후 체계적 전체 수색","밤낮 구분","장비 종류"],"ans":1,"exp":"'rapidly ... most likely survival areas' vs 'thorough, systematic ... after fire controlled'","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"조동사-needn't","q":"You needn't _____ brought extra hose — there was enough on site.","opts":["have","had","to have","to had"],"ans":0,"exp":"needn't have p.p. = 할 필요가 없었는데 했다","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"현재완료","q":"We _____ not yet received confirmation from headquarters.","opts":["have","had","are","were"],"ans":0,"exp":"yet → 현재완료 부정문","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"과거완료","q":"The injured firefighter _____ already been transported when backup arrived.","opts":["has","had","is","was"],"ans":1,"exp":"when+과거 이전 완료 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the civilian evacuation complete before fire attack?\"\n\"All but two units on the seventh floor — they were evacuated during operations.\"\n\nQ: 화재 진압 전 대피 상황은?","opts":["전원 완료","7층 두 세대 제외 완료, 작전 중 대피","전원 미완료","대피 없이 진압 시작"],"ans":1,"exp":"'All but two units on the seventh floor'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Will the structural engineer be on site during the search?\"\n\"Yes, she's already there assessing the load-bearing walls.\"\n\nQ: 구조 엔지니어의 현재 상황은?","opts":["아직 현장 도착 전","이미 내력벽 평가 중","원격으로 지원","취소됨"],"ans":1,"exp":"'already there assessing the load-bearing walls'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"The victim was found on the third floor?\"\n\"Second. The third floor was already fully involved.\"\n\nQ: 피해자가 발견된 층은?","opts":["1층","2층","3층","4층"],"ans":1,"exp":"'Second' → 2층","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is Captain Yoon leading the debrief today?\"\n\"No, she's at headquarters. Lieutenant Cha will cover.\"\n\nQ: 오늘 디브리핑을 이끄는 사람은?","opts":["Yoon 대위","Cha 중위","본부 직원","훈련 코디네이터"],"ans":1,"exp":"'Lieutenant Cha will cover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Why wasn't Rescue 3 at the scene?\"\n\"It was already committed to a call on the east side.\"\n\nQ: Rescue 3가 현장에 없었던 이유는?","opts":["점검 중","동쪽 출동 중","인원 부족","차량 고장"],"ans":1,"exp":"'already committed to a call on the east side'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How long was the response time?\"\n\"Four minutes, twelve seconds — a new record for this district.\"\n\nQ: 대응 시간은?","opts":["3분 12초","4분 12초","5분 12초","6분 12초"],"ans":1,"exp":"'Four minutes, twelve seconds'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"}],[{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the protocol, the accident would not have happened.","opts":["followed","follows","had followed","has followed"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"조동사-should","q":"She should _____ reported the malfunction immediately.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"현재완료","q":"We _____ not yet received confirmation from headquarters.","opts":["have","had","are","were"],"ans":0,"exp":"yet → 현재완료 부정문","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"The lieutenant decided _____ the operation immediately.","opts":["suspend","suspending","to suspend","suspended"],"ans":2,"exp":"decide+to부정사","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"준동사-동명사","q":"The chief avoided _____ the unstable section of the roof.","opts":["to enter","enter","entering","entered"],"ans":2,"exp":"avoid+동명사(V-ing)","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the ladder truck available for the afternoon drill?\"\n\"It just came back from its annual inspection. Should be good.\"\n\nQ: 사다리차 상태는?","opts":["수리 중","연간 점검 복귀, 사용 가능","다른 현장 출동 중","예약됨"],"ans":1,"exp":"'just came back from annual inspection'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is Captain Yoon leading the debrief today?\"\n\"No, she's at headquarters. Lieutenant Cha will cover.\"\n\nQ: 오늘 디브리핑을 이끄는 사람은?","opts":["Yoon 대위","Cha 중위","본부 직원","훈련 코디네이터"],"ans":1,"exp":"'Lieutenant Cha will cover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Has the MAYDAY been called off?\"\n\"Confirmed — the missing firefighter was found on the second floor landing.\"\n\nQ: MAYDAY 해제 이유는?","opts":["화재 진압 완료","실종 소방관 2층 계단참에서 발견","대원 전원 탈출 확인","건물 붕괴 위험 해소"],"ans":1,"exp":"'missing firefighter was found on second floor landing'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"When does the new hose evolution training start?\"\n\"Next Tuesday. Attendance is mandatory for all engine crews.\"\n\nQ: 교육의 특이사항은?","opts":["자율 참석","엔진 팀 전원 의무 참석","특정 팀만 해당","온라인 진행"],"ans":1,"exp":"'mandatory for all engine crews'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Will the structural engineer be on site during the search?\"\n\"Yes, she's already there assessing the load-bearing walls.\"\n\nQ: 구조 엔지니어의 현재 상황은?","opts":["아직 현장 도착 전","이미 내력벽 평가 중","원격으로 지원","취소됨"],"ans":1,"exp":"'already there assessing the load-bearing walls'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the chief approve the new training budget?\"\n\"Partially — she approved the equipment portion but not the travel costs.\"\n\nQ: 승인된 예산 항목은?","opts":["전체 승인","장비 부분만 승인, 출장비 제외","전체 거부","출장비만 승인"],"ans":1,"exp":"'approved the equipment portion but not travel costs'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the protocol, the accident would not have happened.","opts":["followed","follows","had followed","has followed"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"준동사-동명사","q":"She denied _____ the safety log before the inspection.","opts":["to falsify","falsify","falsifying","falsified"],"ans":2,"exp":"deny+동명사(V-ing)","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"관계사-who","q":"The firefighter _____ saved the child received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"조동사-needn't","q":"You needn't _____ brought extra hose — there was enough on site.","opts":["have","had","to have","to had"],"ans":0,"exp":"needn't have p.p. = 할 필요가 없었는데 했다","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How far out is the hazmat team?\"\n\"ETA fifteen minutes. Establish the hot zone and hold until they arrive.\"\n\nQ: 현재 지시사항은?","opts":["즉시 진입","위험 구역 설정 후 HAZMAT 팀 도착까지 대기","철수","민간인 대피 실시"],"ans":1,"exp":"'Establish hot zone and hold until they arrive'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the generator at the training site working?\"\n\"It was fixed yesterday. Should be good to go.\"\n\nQ: 발전기 상태는?","opts":["고장 중","어제 수리 완료, 사용 가능","교체 예정","점검 중"],"ans":1,"exp":"'fixed yesterday. Should be good to go'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"When's the next shift change?\"\n\"0800 tomorrow. The night crew is running a drill at 0600 before handover.\"\n\nQ: 야간 팀의 훈련 시간은?","opts":["0600","0700","0800","0900"],"ans":0,"exp":"'drill at 0600 before handover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the water supply hold during the warehouse fire?\"\n\"We had to switch to the secondary hydrant on Oak Street halfway through.\"\n\nQ: 작전 중 어떤 문제가 발생했는가?","opts":["물 공급 완전 차단","중간에 보조 소화전으로 전환 필요","펌프 고장","호스 파열"],"ans":1,"exp":"'switch to secondary hydrant on Oak Street halfway through'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How long was the response time?\"\n\"Four minutes, twelve seconds — a new record for this district.\"\n\nQ: 대응 시간은?","opts":["3분 12초","4분 12초","5분 12초","6분 12초"],"ans":1,"exp":"'Four minutes, twelve seconds'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did they find the point of origin?\"\n\"Preliminary investigation points to an overloaded outlet in the utility room.\"\n\nQ: 추정 화재 원인은?","opts":["방화","다용도실 과부하 콘센트","가스 누출","담배꽁초"],"ans":1,"exp":"'overloaded outlet in the utility room'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Water flow testing measures static pressure, residual pressure, and flow rate at hydrants. This data is used to design suppression systems and plan tactical water requirements.\"\n\nQ: 수류 시험으로 측정하지 않는 것은?","opts":["정압","잔류 압력","유량","수온"],"ans":3,"exp":"수온(water temperature)은 측정 항목으로 언급되지 않음","passage":"I","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"}],[{"type":"조동사-should","q":"She should _____ reported the malfunction immediately.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"미래완료","q":"By next spring, the new training tower _____ construction.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by next spring → 미래완료(will have p.p.)","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"준동사-동명사","q":"The recruits enjoy _____ in the fitness facility after training.","opts":["to work out","work out","working out","worked out"],"ans":2,"exp":"enjoy+동명사(V-ing)","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"관계사-which","q":"The building, _____ had been abandoned for years, was finally demolished.","opts":["who","which","whose","whom"],"ans":1,"exp":"콤마+사물 선행사 → 계속적 용법 which","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"조동사-ought","q":"The team ought _____ established a command post first.","opts":["have","to have","having","to having"],"ans":1,"exp":"ought to have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"관계사-where","q":"The station _____ he trained for ten years is being renovated.","opts":["where","which","that","who"],"ans":0,"exp":"장소 선행사+부사 역할 → where","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"준동사-동명사","q":"The chief avoided _____ the unstable section of the roof.","opts":["to enter","enter","entering","entered"],"ans":2,"exp":"avoid+동명사(V-ing)","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How far out is the hazmat team?\"\n\"ETA fifteen minutes. Establish the hot zone and hold until they arrive.\"\n\nQ: 현재 지시사항은?","opts":["즉시 진입","위험 구역 설정 후 HAZMAT 팀 도착까지 대기","철수","민간인 대피 실시"],"ans":1,"exp":"'Establish hot zone and hold until they arrive'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Are there enough SCBA units for both crews?\"\n\"Barely — we have eight, and we need ten.\"\n\nQ: SCBA 장비 현황은?","opts":["충분","2개 부족","충분히 남음","전혀 없음"],"ans":1,"exp":"'eight, and we need ten' → 2개 부족","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"When does the new hose evolution training start?\"\n\"Next Tuesday. Attendance is mandatory for all engine crews.\"\n\nQ: 교육의 특이사항은?","opts":["자율 참석","엔진 팀 전원 의무 참석","특정 팀만 해당","온라인 진행"],"ans":1,"exp":"'mandatory for all engine crews'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the ladder truck available for the afternoon drill?\"\n\"It just came back from its annual inspection. Should be good.\"\n\nQ: 사다리차 상태는?","opts":["수리 중","연간 점검 복귀, 사용 가능","다른 현장 출동 중","예약됨"],"ans":1,"exp":"'just came back from annual inspection'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"분사구문","q":"_____ the building thoroughly, the team found no survivors.","opts":["Search","Searching","Searched","Having searched"],"ans":3,"exp":"분사구문: Having p.p. = 완료된 동작 후 주절","section":"문법"},{"type":"과거완료","q":"The injured firefighter _____ already been transported when backup arrived.","opts":["has","had","is","was"],"ans":1,"exp":"when+과거 이전 완료 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"준동사-동명사","q":"The recruits enjoy _____ in the fitness facility after training.","opts":["to work out","work out","working out","worked out"],"ans":2,"exp":"enjoy+동명사(V-ing)","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"조동사-needn't","q":"You needn't _____ brought extra hose — there was enough on site.","opts":["have","had","to have","to had"],"ans":0,"exp":"needn't have p.p. = 할 필요가 없었는데 했다","section":"문법"},{"type":"현재완료","q":"It is the first time she _____ a multi-story rescue.","opts":["leads","led","has led","had led"],"ans":2,"exp":"It is the first time ~ → 현재완료","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"수동태-완료","q":"The building _____ abandoned for years before it was renovated.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"준동사-동명사","q":"She denied _____ the safety log before the inspection.","opts":["to falsify","falsify","falsifying","falsified"],"ans":2,"exp":"deny+동명사(V-ing)","section":"문법"},{"type":"준동사-to부정사","q":"The department plans _____ all units with new radios.","opts":["equip","equipping","to equip","equipped"],"ans":2,"exp":"plan+to부정사","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"조동사-ought","q":"The team ought _____ established a command post first.","opts":["have","to have","having","to having"],"ans":1,"exp":"ought to have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"관계사-whom","q":"The officer to _____ the report was sent is now reviewing it.","opts":["who","which","whose","whom"],"ans":3,"exp":"전치사+목적격 관계사 → whom","section":"문법"},{"type":"관계사-which","q":"The building, _____ had been abandoned for years, was finally demolished.","opts":["who","which","whose","whom"],"ans":1,"exp":"콤마+사물 선행사 → 계속적 용법 which","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"현재완료","q":"The battalion chief _____ this station for ten years.","opts":["commands","commanded","has commanded","had commanded"],"ans":2,"exp":"for+기간 → 현재완료","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"미래완료","q":"By next spring, the new training tower _____ construction.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by next spring → 미래완료(will have p.p.)","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is Captain Yoon leading the debrief today?\"\n\"No, she's at headquarters. Lieutenant Cha will cover.\"\n\nQ: 오늘 디브리핑을 이끄는 사람은?","opts":["Yoon 대위","Cha 중위","본부 직원","훈련 코디네이터"],"ans":1,"exp":"'Lieutenant Cha will cover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How many units responded to the apartment fire?\"\n\"Five engines, two ladders, and one rescue.\"\n\nQ: 출동한 사다리차 수는?","opts":["1대","2대","3대","5대"],"ans":1,"exp":"'two ladders'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"How far out is the hazmat team?\"\n\"ETA fifteen minutes. Establish the hot zone and hold until they arrive.\"\n\nQ: 현재 지시사항은?","opts":["즉시 진입","위험 구역 설정 후 HAZMAT 팀 도착까지 대기","철수","민간인 대피 실시"],"ans":1,"exp":"'Establish hot zone and hold until they arrive'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the civilian evacuation complete before fire attack?\"\n\"All but two units on the seventh floor — they were evacuated during operations.\"\n\nQ: 화재 진압 전 대피 상황은?","opts":["전원 완료","7층 두 세대 제외 완료, 작전 중 대피","전원 미완료","대피 없이 진압 시작"],"ans":1,"exp":"'All but two units on the seventh floor'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Should we request mutual aid?\"\n\"Not yet — let's see if the second unit can handle it.\"\n\nQ: 상호지원 요청 여부는?","opts":["즉시 요청","아직 보류","이미 요청","불필요"],"ans":1,"exp":"'Not yet — let's see if second unit can handle it'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did anyone get hurt at yesterday's call?\"\n\"One firefighter — minor burn on the left arm. He's back on duty.\"\n\nQ: 부상자 현황은?","opts":["부상 없음","소방관 1명 경상, 복귀","소방관 2명 부상","민간인 1명 부상"],"ans":1,"exp":"'One firefighter — minor burn ... back on duty'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"ICS uses a modular organization that expands or contracts based on incident needs. A large event may activate all five functional sections: Operations, Planning, Logistics, Finance/Administration, and Command Staff.\"\n\nQ: 지문에서 'modular'의 의미는?","opts":["fixed","expandable as needed","temporary","circular"],"ans":1,"exp":"modular = 필요에 따라 확장·축소 가능","passage":"A","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"\"Primary search is conducted rapidly after fire attack begins, covering the most likely survival areas first. Secondary search is a thorough, systematic search of the entire structure after the fire is controlled.\"\n\nQ: 1차 수색과 2차 수색의 차이는?","opts":["수색 팀 수","빠른 주요 지역 vs 통제 후 체계적 전체 수색","밤낮 구분","장비 종류"],"ans":1,"exp":"'rapidly ... most likely survival areas' vs 'thorough, systematic ... after fire controlled'","passage":"J","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"}],[{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"현재완료","q":"He _____ never entered a burning structure without full PPE.","opts":["has","had","is","was"],"ans":0,"exp":"never → 현재완료와 함께 사용, has never p.p.","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"현재완료","q":"We _____ not yet received confirmation from headquarters.","opts":["have","had","are","were"],"ans":0,"exp":"yet → 현재완료 부정문","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"현재완료","q":"She _____ her certification exam three times already.","opts":["passes","passed","has passed","had passed"],"ans":2,"exp":"already → 현재완료 신호어","section":"문법"},{"type":"과거완료","q":"The injured firefighter _____ already been transported when backup arrived.","opts":["has","had","is","was"],"ans":1,"exp":"when+과거 이전 완료 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"type":"과거완료","q":"They discovered that someone _____ tampered with the equipment.","opts":["has","had","is","was"],"ans":1,"exp":"발견(과거) 이전 행위 → 과거완료(had p.p.)","section":"문법"},{"type":"과거완료","q":"The fire _____ for two hours before the rain extinguished it.","opts":["burned","has burned","had been burning","was burning"],"ans":2,"exp":"before+과거 → 과거완료진행(had been V-ing)","section":"문법"},{"type":"조동사-could","q":"With better equipment, we could _____ reached the victim sooner.","opts":["have","had","be","has"],"ans":0,"exp":"could have p.p. = 할 수 있었을 텐데(과거 가능성)","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the protocol, the accident would not have happened.","opts":["followed","follows","had followed","has followed"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"조동사-needn't","q":"You needn't _____ brought extra hose — there was enough on site.","opts":["have","had","to have","to had"],"ans":0,"exp":"needn't have p.p. = 할 필요가 없었는데 했다","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"가정법 과거","q":"If we _____ more personnel, the rescue operation would be faster.","opts":["have","had","has","is having"],"ans":1,"exp":"가정법 과거: If+had(과거), would+원형","section":"문법"},{"type":"가정법 과거완료","q":"If the alarm _____ earlier, everyone could have escaped.","opts":["sounds","sounded","had sounded","has sounded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., could have p.p.","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did they find the point of origin?\"\n\"Preliminary investigation points to an overloaded outlet in the utility room.\"\n\nQ: 추정 화재 원인은?","opts":["방화","다용도실 과부하 콘센트","가스 누출","담배꽁초"],"ans":1,"exp":"'overloaded outlet in the utility room'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the generator at the training site working?\"\n\"It was fixed yesterday. Should be good to go.\"\n\nQ: 발전기 상태는?","opts":["고장 중","어제 수리 완료, 사용 가능","교체 예정","점검 중"],"ans":1,"exp":"'fixed yesterday. Should be good to go'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"The victim was found on the third floor?\"\n\"Second. The third floor was already fully involved.\"\n\nQ: 피해자가 발견된 층은?","opts":["1층","2층","3층","4층"],"ans":1,"exp":"'Second' → 2층","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the water supply hold during the warehouse fire?\"\n\"We had to switch to the secondary hydrant on Oak Street halfway through.\"\n\nQ: 작전 중 어떤 문제가 발생했는가?","opts":["물 공급 완전 차단","중간에 보조 소화전으로 전환 필요","펌프 고장","호스 파열"],"ans":1,"exp":"'switch to secondary hydrant on Oak Street halfway through'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'residual'의 의미는?","opts":["maximum","remaining after use","theoretical","initial"],"ans":1,"exp":"residual = 잔류하는, 남아있는(remaining after use)","passage":"I","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"조동사-must","q":"He must _____ left his radio at the station — he can't reach anyone.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측(분명히 ~했을 것이다)","section":"문법"},{"type":"준동사-동명사","q":"She denied _____ the safety log before the inspection.","opts":["to falsify","falsify","falsifying","falsified"],"ans":2,"exp":"deny+동명사(V-ing)","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"준동사-동명사","q":"The recruits enjoy _____ in the fitness facility after training.","opts":["to work out","work out","working out","worked out"],"ans":2,"exp":"enjoy+동명사(V-ing)","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"조동사-needn't","q":"You needn't _____ brought extra hose — there was enough on site.","opts":["have","had","to have","to had"],"ans":0,"exp":"needn't have p.p. = 할 필요가 없었는데 했다","section":"문법"},{"type":"관계사-when","q":"He remembered the day _____ the station first opened.","opts":["where","which","when","what"],"ans":2,"exp":"시간 선행사+부사 역할 → when","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"관계사-where","q":"The station _____ he trained for ten years is being renovated.","opts":["where","which","that","who"],"ans":0,"exp":"장소 선행사+부사 역할 → where","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"과거완료","q":"The alarm _____ already sounded twice before anyone responded.","opts":["has","had","is","was"],"ans":1,"exp":"before ~ → 과거완료(had p.p.)","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"준동사-동명사","q":"The chief avoided _____ the unstable section of the roof.","opts":["to enter","enter","entering","entered"],"ans":2,"exp":"avoid+동명사(V-ing)","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"접속사","q":"She studied hard _____ she could pass the certification exam.","opts":["so that","in order","because of","despite"],"ans":0,"exp":"so that ~ = ~하기 위해(목적절)","section":"문법"},{"type":"수동태","q":"The new protocol _____ introduced last month.","opts":["is","was","has","had"],"ans":1,"exp":"last month = 과거 → was+p.p.","section":"문법"},{"type":"과거완료","q":"She _____ never seen such a large wildfire before that day.","opts":["has","had","is","was"],"ans":1,"exp":"before that day → 과거완료(had p.p.)","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"관계사-whose","q":"The engineer _____ calculations were incorrect resigned last week.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"type":"미래완료","q":"By December, she _____ in this department for twenty years.","opts":["works","worked","will work","will have worked"],"ans":3,"exp":"by December → 미래완료(will have p.p.)","section":"문법"},{"type":"관계사-which","q":"The building, _____ had been abandoned for years, was finally demolished.","opts":["who","which","whose","whom"],"ans":1,"exp":"콤마+사물 선행사 → 계속적 용법 which","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the new accountability system active yet?\"\n\"It went live this morning. Everyone needs to register by noon.\"\n\nQ: 새 시스템의 등록 마감 시간은?","opts":["오전 9시","정오","오후 3시","오늘 자정"],"ans":1,"exp":"'register by noon'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is Captain Yoon leading the debrief today?\"\n\"No, she's at headquarters. Lieutenant Cha will cover.\"\n\nQ: 오늘 디브리핑을 이끄는 사람은?","opts":["Yoon 대위","Cha 중위","본부 직원","훈련 코디네이터"],"ans":1,"exp":"'Lieutenant Cha will cover'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the generator at the training site working?\"\n\"It was fixed yesterday. Should be good to go.\"\n\nQ: 발전기 상태는?","opts":["고장 중","어제 수리 완료, 사용 가능","교체 예정","점검 중"],"ans":1,"exp":"'fixed yesterday. Should be good to go'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Was the fire contained to the unit of origin?\"\n\"Mostly — there was some extension to the adjacent unit through the attic.\"\n\nQ: 화재 확산 상황은?","opts":["완전 차단","다락을 통해 인접 세대로 일부 확산","전체 층으로 확산","건물 전체 소실"],"ans":1,"exp":"'some extension to adjacent unit through attic'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Who submitted the after-action report?\"\n\"Sergeant Kim did — she filed it right after the debrief.\"\n\nQ: 보고서를 제출한 사람은?","opts":["지휘관","Kim 하사","훈련 코디네이터","부서장"],"ans":1,"exp":"'Sergeant Kim did'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Have you seen the new SOG for hazmat responses?\"\n\"It's on the shared drive. I haven't read it yet.\"\n\nQ: 새 SOG에 대해 알 수 있는 것은?","opts":["아직 배포 안 됨","공유 드라이브에 있고 남성은 아직 안 읽음","삭제되었음","인쇄본만 존재"],"ans":1,"exp":"'on the shared drive. I haven't read it yet'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Why wasn't Rescue 3 at the scene?\"\n\"It was already committed to a call on the east side.\"\n\nQ: Rescue 3가 현장에 없었던 이유는?","opts":["점검 중","동쪽 출동 중","인원 부족","차량 고장"],"ans":1,"exp":"'already committed to a call on the east side'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"\"The incident command system (ICS) was developed in California following a series of catastrophic wildfires that exposed shortcomings in multi-agency coordination. ICS introduced a standardized management structure applicable to any incident type.\"\n\nQ: ICS 개발의 직접적 원인은?","opts":["새 장비 필요성","다기관 조율 실패","연방 의무화","예산 삭감"],"ans":1,"exp":"'exposed shortcomings in multi-agency coordination'","passage":"A","section":"독해"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Modern fire behavior has changed due to increased synthetic materials in furnishings. Synthetic materials release energy at a much higher rate, reducing time to flashover from approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재가 화재에 미치는 주요 영향은?","opts":["연소 지연","플래시오버까지 시간 급감","연기 감소","열 방출 감소"],"ans":1,"exp":"'reducing time to flashover from 20 minutes to 3-4 minutes'","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"Research shows NTS deficiencies contribute to a majority of critical incidents in emergency services. Tunnel vision — fixation on a single task at the expense of broader awareness — is one of the most commonly cited NTS failures.\"\n\nQ: '터널 비전(tunnel vision)'이란?","opts":["다중 임무 동시 처리","하나의 과제에 집중해 전체 인식 상실","팀원 간 소통 부재","장비 과신"],"ans":1,"exp":"'fixation on a single task at the expense of broader awareness'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Post-traumatic stress disorder (PTSD), depression, and anxiety affect a disproportionate number of first responders. Firefighters are more likely to die by suicide than in the line of duty.\"\n\nQ: 지문에서 'disproportionate'의 의미는?","opts":["average","excessively high","decreasing","expected"],"ans":1,"exp":"disproportionate = 불균형하게 높은(excessively high)","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"Firefighters typically use elevators only to a floor two stories below the reported fire floor. This reduces risks of power failure, smoke infiltration, and entrapment.\"\n\nQ: 엘리베이터를 화재층 2층 아래까지만 사용하는 이유는?","opts":["에너지 절약","정전·연기 침투·갇힘 위험 감소","건물 규정 준수","속도 향상"],"ans":1,"exp":"'reduces risks of power failure, smoke infiltration, and entrapment'","passage":"E","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Decontamination removes hazardous materials from personnel and equipment. The sequence — gross decon, formal decon, medical monitoring — must be followed in order to prevent secondary contamination.\"\n\nQ: 오염 제거 절차의 목적은?","opts":["장비 재사용","2차 오염 방지","법적 요건 충족","비용 절감"],"ans":1,"exp":"'must be followed in order to prevent secondary contamination'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'topography'의 의미는?","opts":["weather patterns","land surface features","fuel types","wind direction"],"ans":1,"exp":"topography = 지형, 지세(land surface features)","passage":"G","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"\"Structural collapse is one of the most dangerous hazards in firefighting. Warning signs include cracking sounds, sagging floors, distorted door frames, and visible cracks in load-bearing walls.\"\n\nQ: 구조 붕괴 경고 신호가 아닌 것은?","opts":["균열음","바닥 처짐","문틀 변형","강한 연기 냄새"],"ans":3,"exp":"강한 연기 냄새는 구조 붕괴 경고 신호로 언급되지 않음","passage":"H","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"Q: 지문에서 'atmospheric'의 의미는?","opts":["structural","relating to the air/environment","thermal","chemical"],"ans":1,"exp":"atmospheric = 대기의, 공기 환경에 관한","passage":"J","section":"독해"},{"q":"\"Positive pressure ventilation (PPV) pushes fresh air into a structure from one side while smoke and heat exit from the opposite side. Proper coordination with attack crews is essential for PPV to be effective.\"\n\nQ: PPV 효과를 위한 핵심 조건은?","opts":["충분한 물 공급","진압 팀과의 적절한 조율","고출력 팬 사용","특정 기상 조건"],"ans":1,"exp":"'Proper coordination with attack crews is essential'","passage":"J","section":"독해"}],[{"type":"현재완료","q":"The department _____ its safety record since the new chief arrived.","opts":["improves","improved","has improved","had improved"],"ans":2,"exp":"since+과거절 → 현재완료","section":"문법"},{"type":"병렬","q":"The officer is responsible for planning, coordinating, and _____ resources.","opts":["manage","to manage","managing","managed"],"ans":2,"exp":"병렬 구조: V-ing, V-ing, and V-ing","section":"문법"},{"type":"준동사-동명사","q":"She denied _____ the safety log before the inspection.","opts":["to falsify","falsify","falsifying","falsified"],"ans":2,"exp":"deny+동명사(V-ing)","section":"문법"},{"type":"가정법 과거","q":"If the ladder _____ longer, we could reach the fifth floor.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"조동사-might","q":"The cause of the explosion might _____ been a gas leak.","opts":["have","had","be","has"],"ans":0,"exp":"might have p.p. = 과거 약한 추측","section":"문법"},{"type":"수동태","q":"All personnel _____ notified of the drill cancellation.","opts":["were","was","has been","had"],"ans":0,"exp":"복수 주어+과거 수동태: were+p.p.","section":"문법"},{"type":"현재완료","q":"The station _____ its equipment three times this year.","opts":["upgrades","upgraded","has upgraded","had upgraded"],"ans":2,"exp":"this year → 현재완료(has p.p.)","section":"문법"},{"type":"현재완료","q":"The recruits _____ just completed their physical fitness evaluation.","opts":["has","have","had","are"],"ans":1,"exp":"just → 현재완료(have just p.p.)","section":"문법"},{"type":"준동사-동명사","q":"The officer suggested _____ the drill schedule.","opts":["to revise","revise","revising","revised"],"ans":2,"exp":"suggest+동명사(V-ing)","section":"문법"},{"type":"미래완료","q":"By next spring, the new training tower _____ construction.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by next spring → 미래완료(will have p.p.)","section":"문법"},{"type":"현재완료","q":"They _____ already submitted the incident report.","opts":["have","had","are","were"],"ans":0,"exp":"already → 현재완료(have p.p.)","section":"문법"},{"type":"가정법 과거","q":"If every officer _____ this manual, fewer errors would occur.","opts":["reads","read","were reading","has read"],"ans":1,"exp":"가정법 과거: If+과거동사, would+원형","section":"문법"},{"type":"현재완료","q":"The crew _____ on standby for six hours.","opts":["is","was","has been","had been"],"ans":2,"exp":"for+기간, 현재까지 → 현재완료(has been)","section":"문법"},{"type":"과거완료","q":"By the time the chief arrived, the crew _____ already secured the perimeter.","opts":["has","had","have","is"],"ans":1,"exp":"by the time+과거 → 과거완료(had p.p.)","section":"문법"},{"type":"준동사-to부정사","q":"She wants _____ the advanced certification before next year.","opts":["earn","earning","to earn","earned"],"ans":2,"exp":"want+to부정사","section":"문법"},{"type":"가정법 과거완료","q":"The outcome would have been different if they _____ better prepared.","opts":["are","were","had been","have been"],"ans":2,"exp":"If+had been → 가정법 과거완료","section":"문법"},{"type":"미래완료","q":"By the time you arrive, the team _____ the drill.","opts":["finishes","finished","will finish","will have finished"],"ans":3,"exp":"by the time+현재절 → 미래완료","section":"문법"},{"type":"관계사-what","q":"_____ impressed the evaluators most was the team's communication.","opts":["That","Which","What","Who"],"ans":2,"exp":"선행사 없는 명사절 → What","section":"문법"},{"type":"가정법 도치","q":"_____ the incident commander received the data earlier, he could have acted sooner.","opts":["If","Had","Should","Were"],"ans":1,"exp":"Had+주어+p.p. = 가정법 과거완료 도치","section":"문법"},{"type":"현재완료","q":"Has the investigator _____ the origin of the fire yet?","opts":["determines","determined","determining","determine"],"ans":1,"exp":"Has+주어+p.p. → 현재완료 의문문","section":"문법"},{"type":"수동태","q":"The damaged gear _____ replaced before the next shift.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"접속사","q":"_____ the weather was bad, the drill proceeded as scheduled.","opts":["Despite","Although","Because","So that"],"ans":1,"exp":"Although = 비록 ~이지만(양보절)","section":"문법"},{"type":"수동태-완료","q":"The report _____ submitted by the time the chief arrived.","opts":["is","was","has been","had been"],"ans":3,"exp":"by the time+과거 → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"조동사-needn't","q":"You needn't _____ brought extra hose — there was enough on site.","opts":["have","had","to have","to had"],"ans":0,"exp":"needn't have p.p. = 할 필요가 없었는데 했다","section":"문법"},{"type":"현재완료","q":"The fire department _____ the new protocol since January.","opts":["implements","implemented","has implemented","had implemented"],"ans":2,"exp":"since+시점 → 현재완료(has p.p.)","section":"문법"},{"type":"가정법 도치","q":"_____ there an emergency, press the red button immediately.","opts":["If","Were","Had","Should"],"ans":1,"exp":"Were there = If there were → 가정법 과거 도치","section":"문법"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the training coordinator confirm the date?\"\n\"She did — it's been moved to the 22nd.\"\n\nQ: 무엇이 변경되었는가?","opts":["훈련 취소","훈련 날짜가 22일로 변경","훈련 장소 변경","훈련 담당자 변경"],"ans":1,"exp":"'moved to the 22nd' → 날짜 변경","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Are there enough SCBA units for both crews?\"\n\"Barely — we have eight, and we need ten.\"\n\nQ: SCBA 장비 현황은?","opts":["충분","2개 부족","충분히 남음","전혀 없음"],"ans":1,"exp":"'eight, and we need ten' → 2개 부족","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Should we request mutual aid?\"\n\"Not yet — let's see if the second unit can handle it.\"\n\nQ: 상호지원 요청 여부는?","opts":["즉시 요청","아직 보류","이미 요청","불필요"],"ans":1,"exp":"'Not yet — let's see if second unit can handle it'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the chief approve the new training budget?\"\n\"Partially — she approved the equipment portion but not the travel costs.\"\n\nQ: 승인된 예산 항목은?","opts":["전체 승인","장비 부분만 승인, 출장비 제외","전체 거부","출장비만 승인"],"ans":1,"exp":"'approved the equipment portion but not travel costs'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Is the ladder truck available for the afternoon drill?\"\n\"It just came back from its annual inspection. Should be good.\"\n\nQ: 사다리차 상태는?","opts":["수리 중","연간 점검 복귀, 사용 가능","다른 현장 출동 중","예약됨"],"ans":1,"exp":"'just came back from annual inspection'","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"The victim was found on the third floor?\"\n\"Second. The third floor was already fully involved.\"\n\nQ: 피해자가 발견된 층은?","opts":["1층","2층","3층","4층"],"ans":1,"exp":"'Second' → 2층","section":"청취"},{"part":1,"q":"[Part 1 — 짧은 대화]\n\n\"Did the water supply hold during the warehouse fire?\"\n\"We had to switch to the secondary hydrant on Oak Street halfway through.\"\n\nQ: 작전 중 어떤 문제가 발생했는가?","opts":["물 공급 완전 차단","중간에 보조 소화전으로 전환 필요","펌프 고장","호스 파열"],"ans":1,"exp":"'switch to secondary hydrant on Oak Street halfway through'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n두 소방관이 출동 후 장비 상태를 점검합니다.\n\n\"The thermal imaging camera worked perfectly, but the portable radio lost signal twice during interior operations.\"\n\"Was it interference from the structure or battery issue?\"\n\"The battery was fully charged. My guess is structural interference — lots of rebar in those walls.\"\n\"We should log it and flag it for the tech team.\"\n\nQ: 무선 통신 문제의 추정 원인은?","opts":["배터리 방전","건물 내 철근에 의한 구조적 간섭","소프트웨어 오류","주파수 충돌"],"ans":1,"exp":"'structural interference — lots of rebar in those walls'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"Should we request new radios from supply?\"\n\"Not yet — let's document this incident and see if it happens again. If it does, we escalate.\"\n\nQ: 다음 조치로 결정된 것은?","opts":["즉시 새 장비 요청","사건 기록 후 반복 시 보고","무선기 교체 의뢰","현장 재방문"],"ans":1,"exp":"'document this incident and see if it happens again. If it does, we escalate'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n지휘관과 대원이 인원 배치에 대해 논의합니다.\n\n\"We're short three people this shift because of the mandatory medical leave.\"\n\"Can we pull from the reserve pool?\"\n\"I've already requested two. The third will have to wait until the union clears it.\"\n\"That could take days.\"\n\nQ: 이번 교대 인원이 부족한 이유는?","opts":["교육 참석","의무 의료 휴가","파업","자발적 결근"],"ans":1,"exp":"'short three people ... mandatory medical leave'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What happens if we're dispatched to a major incident understaffed?\"\n\"We request mutual aid immediately and activate the duty officer protocol.\"\n\nQ: 인원 부족 상태에서 대규모 사고 출동 시 조치는?","opts":["출동 거부","상호지원 요청 및 당직 프로토콜 가동","경찰 지원 요청","본부에 즉시 보고"],"ans":1,"exp":"'request mutual aid immediately and activate duty officer protocol'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n훈련 평가 후 피드백 대화입니다.\n\n\"Your team's forcible entry was textbook — well done. But the hose advance took almost ninety seconds longer than the benchmark.\"\n\"We had difficulty getting the line through the rear door — the hinge was on an unusual side.\"\n\"Good situational awareness. That needs to go in your after-action report.\"\n\nQ: 팀의 강점으로 평가된 것은?","opts":["호스 전개 속도","강제 진입 기술","통신","수색 패턴"],"ans":1,"exp":"'forcible entry was textbook — well done'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n(위 대화 계속)\n\n\"What's the main item for improvement?\"\n\"Time on the hose advance. We want to see it under the benchmark next drill.\"\n\nQ: 개선해야 할 주요 항목은?","opts":["강제 진입 속도","호스 전개 시간 단축","무전 규율","안전 장비 착용"],"ans":1,"exp":"'Time on the hose advance. We want to see it under benchmark'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방서 공지사항입니다.\n\n\"Due to the ongoing drought conditions and red-flag weather warnings, all outdoor training activities involving live fire are suspended until further notice. Indoor training and simulation exercises will continue as scheduled. Stay alert for additional dispatch requests as wildfire risk remains elevated.\"\n\nQ: 현재 중단된 활동은?","opts":["실내 훈련","시뮬레이션 훈련","야외 실화재 훈련","추가 출동"],"ans":2,"exp":"'outdoor training involving live fire are suspended'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n안전 브리핑입니다.\n\n\"Today we review our mayday procedures. When a firefighter calls a mayday, all non-essential radio traffic must cease immediately. The IC will assign a separate channel for mayday operations. The RIT team activates and a PAR is conducted for all interior crews. Repeat: all non-essential traffic stops — only mayday channel stays open.\"\n\nQ: MAYDAY 선언 즉시 발생해야 하는 것은?","opts":["전 대원 철수","불필요한 무선 교신 중단 및 RIT 가동","물 공급 증가","지원 요청"],"ans":1,"exp":"'all non-essential radio traffic must cease ... RIT team activates'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n현장 브리핑입니다.\n\n\"We have a working fire in a three-story Type III ordinary construction building. Reports indicate two occupants unaccounted for on the upper floors. Engine 1 and 3 — attack lines to the second floor. Truck 2 — aerial to the rear for search. Rescue 1 — RIT. All other units hold at staging.\"\n\nQ: Rescue 1의 임무는?","opts":["화재 진압","2층 수색","공중 지원","신속대응팀(RIT)"],"ans":3,"exp":"'Rescue 1 — RIT'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n교육 공지입니다.\n\n\"All company officers must complete the updated incident command refresher course by the end of the third quarter. The course is available online and in-person. Online completion counts for two CEU credits; in-person completion counts for four. Officers are encouraged to attend in-person when scheduling allows.\"\n\nQ: 대면 교육과 온라인 교육의 차이점은?","opts":["대면만 인정","온라인 2점, 대면 4점 CEU 부여","동일한 크레딧","대면은 필수, 온라인 선택"],"ans":1,"exp":"'Online ... two CEU credits; in-person ... four'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n훈련 안내 방송입니다.\n\n\"This week's confined space drill will be conducted in three rotations. Group A goes first at 0800, Group B at 1000, and Group C at 1300. All participants must attend the safety briefing at 0730 regardless of their rotation. Failure to attend the briefing will result in removal from the drill.\"\n\nQ: 0730 안전 브리핑 참석 대상은?","opts":["Group A만","Group B와 C만","전 참가자","각 그룹 대표"],"ans":1,"exp":"'all participants must attend ... at 0730 regardless of their rotation'","section":"청취"},{"part":3,"q":"[Part 3 — 담화문]\n\n소방청 공지입니다.\n\n\"Attention all units. Effective immediately, personnel responding to structure fires must conduct a 360-degree walk-around of the building before committing to interior operations, unless an immediate life-safety rescue is required. This procedure is now mandatory per the updated tactical guidelines.\"\n\nQ: 즉각 인명 구조가 필요하지 않은 경우, 내부 진입 전 의무 조치는?","opts":["건물 사진 촬영","360도 외부 점검","물 공급 확인","지휘소 설치"],"ans":1,"exp":"'conduct a 360-degree walk-around before committing to interior operations'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n소방 전술 강의입니다.\n\n\"Today we'll discuss the concept of risk management on the fireground. The RECEO-VS model provides a framework: Rescue, Exposure, Confinement, Extinguishment, Overhaul, Ventilation, and Salvage. Commanders prioritize these in order, with life safety always first. Rescue operations take precedence over all other tactical objectives.\"\n\nQ: RECEO-VS 모델에서 가장 먼저 우선시되는 것은?","opts":["화재 진압","노출 보호","구조","잔화 정리"],"ans":2,"exp":"'Rescue operations take precedence over all other tactical objectives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Ventilation and Salvage are placed at the end of the priority list not because they are unimportant, but because they support and follow the primary tactical objectives. Without successful rescue and confinement, ventilation may actually accelerate the fire.\"\n\nQ: 환기(Ventilation)가 위험할 수 있는 경우는?","opts":["구조와 차단이 성공적으로 이루어진 후","구조와 차단이 이루어지지 않은 상태에서","야간 작전 중","다층 건물에서"],"ans":1,"exp":"'Without successful rescue and confinement, ventilation may actually accelerate the fire'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n비기술적 역량 강의입니다.\n\n\"Non-technical skills — or NTS — are broadly defined as cognitive, social, and personal resource skills that complement technical skills in the workplace. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership. Research consistently shows that NTS deficiencies contribute to a majority of critical incidents.\"\n\nQ: NTS 결함이 미치는 영향은?","opts":["장비 수명 단축","대부분의 중대 사고에 기여","훈련 비용 증가","인력 이탈"],"ans":1,"exp":"'NTS deficiencies contribute to a majority of critical incidents'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"Situational awareness — the most foundational NTS — can be broken into three levels: perception of elements in the environment, comprehension of the current situation, and projection of future status. Loss of situational awareness at any level can cascade into serious errors in judgment.\"\n\nQ: 상황인식의 세 가지 수준 중 마지막 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n현장지휘 강의입니다.\n\n\"Effective incident command requires a clear span of control. Research from military and emergency services suggests that a supervisor can effectively manage between three and seven subordinates, with five being the optimal number. Exceeding this span leads to coordination breakdowns and increased error rates.\"\n\nQ: 최적의 통솔 범위(span of control)는?","opts":["3명","5명","7명","10명"],"ans":1,"exp":"'five being the optimal number'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n(위 강의 계속)\n\n\"When incident complexity grows and the span of control is exceeded, additional layers of management must be added. This is why ICS uses branches, divisions, and groups to maintain manageable spans at every level of the command structure.\"\n\nQ: 통솔 범위 초과 시 ICS의 대응 방식은?","opts":["지휘관 교체","지부·부서·그룹 추가로 계층 확대","전체 철수","상호지원 요청"],"ans":1,"exp":"'uses branches, divisions, and groups to maintain manageable spans'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n화재 행동 강의입니다.\n\n\"Modern fire behavior has changed significantly due to the increased use of synthetic materials in furnishings and construction. Compared to legacy fuels, synthetic materials release energy at a much higher rate, reducing the time to flashover from the historical average of approximately 20 minutes to as little as 3 to 4 minutes in some studies.\"\n\nQ: 합성 소재로 인해 플래시오버까지 시간이 어떻게 변했는가?","opts":["20분에서 30분으로 증가","20분에서 3~4분으로 대폭 감소","변화 없음","10분에서 5분으로 감소"],"ans":1,"exp":"'from approximately 20 minutes to as little as 3 to 4 minutes'","section":"청취"},{"q":"Q: ICS의 5개 기능 섹션이 아닌 것은?","opts":["Operations","Planning","Training","Logistics"],"ans":2,"exp":"Training은 ICS 공식 섹션이 아님","passage":"A","section":"독해"},{"q":"\"Unity of command ensures that each individual reports to only one supervisor. This is critical in multi-agency incidents where personnel from different organizations must work together.\"\n\nQ: 단일지휘 원칙이 특히 중요한 상황은?","opts":["소규모 단일 기관 사고","다기관 참여 사고","야간 사고","실내 사고"],"ans":1,"exp":"'critical in multi-agency incidents'","passage":"A","section":"독해"},{"q":"\"Under ICS, every position, function, and resource type has a single standardized name used by all participating organizations. This common terminology eliminates confusion during joint operations.\"\n\nQ: 공통 용어 사용의 목적은?","opts":["비용 절감","혼란 제거","훈련 시간 단축","장비 표준화"],"ans":1,"exp":"'eliminates confusion during joint operations'","passage":"A","section":"독해"},{"q":"\"The fire tetrahedron consists of four elements: fuel, oxygen, heat, and chemical chain reaction. Suppressing any one element will extinguish the fire. Modern suppression agents target different elements.\"\n\nQ: 지문에서 'suppressing'의 의미는?","opts":["increasing","eliminating/reducing","observing","documenting"],"ans":1,"exp":"suppressing = 억제하다, 제거하다","passage":"B","section":"독해"},{"q":"\"Thermal layering creates distinct temperature zones within a burning structure. The hottest gases accumulate near the ceiling while cooler, more breathable air remains near the floor.\"\n\nQ: 화재 현장 바닥 근처 공기의 특성은?","opts":["가장 뜨겁고 독성이 강함","더 시원하고 호흡 가능","산소가 전혀 없음","연기가 가장 짙음"],"ans":1,"exp":"'cooler, more breathable air remains near the floor'","passage":"B","section":"독해"},{"q":"\"Flashover occurs when ceiling temperatures reach approximately 600 degrees Celsius, causing near-simultaneous ignition of all combustible materials in a compartment. Warning signs include darkening smoke and intense radiant heat.\"\n\nQ: 플래시오버 경고 신호가 아닌 것은?","opts":["천장 온도 600°C 접근","짙어지는 연기","강렬한 복사열","갑작스러운 바람"],"ans":3,"exp":"갑작스러운 바람은 언급되지 않은 경고 신호","passage":"B","section":"독해"},{"q":"\"Situational awareness has three levels: perception of environmental elements, comprehension of the current situation, and projection of future status. Loss of SA at any level can cascade into serious judgment errors.\"\n\nQ: 상황인식의 세 번째 단계는?","opts":["환경 요소 지각","현재 상황 이해","미래 상태 예측","팀 의사소통"],"ans":2,"exp":"'projection of future status' → 미래 상태 예측","passage":"C","section":"독해"},{"q":"\"CRM — crew resource management — was originally developed in aviation after cockpit errors caused multiple fatal accidents. Fire services adopted CRM principles to improve teamwork and communication under stress.\"\n\nQ: CRM의 발원지는?","opts":["군사 작전","항공 산업","해운 산업","의료 분야"],"ans":1,"exp":"'originally developed in aviation'","passage":"C","section":"독해"},{"q":"\"Non-technical skills (NTS) are cognitive, social, and personal resource skills that complement technical skills. In emergency services, NTS includes situational awareness, decision-making, communication, teamwork, and leadership.\"\n\nQ: NTS에 포함되지 않는 것은?","opts":["상황인식","의사결정","장비 조작","팀워크"],"ans":2,"exp":"장비 조작(equipment operation)은 기술적 역량(technical skill)","passage":"C","section":"독해"},{"q":"\"Peer support programs and critical incident stress debriefing (CISD) are among the most used mental health tools. Their effectiveness depends largely on departments normalizing help-seeking behavior.\"\n\nQ: 정신 건강 프로그램의 효과를 결정하는 핵심 요소는?","opts":["프로그램 비용","도움 요청 정상화 문화","참가자 수","세션 길이"],"ans":1,"exp":"'effectiveness depends on normalizing help-seeking behavior'","passage":"D","section":"독해"},{"q":"\"Cancer now accounts for a higher percentage of firefighter deaths than any other cause. Gross decontamination — removing contaminated gear at the scene — significantly reduces skin absorption of carcinogens.\"\n\nQ: 현재 소방관 사망 원인 1위는?","opts":["현장 부상","심장 질환","암","차량 사고"],"ans":2,"exp":"'cancer now accounts for a higher percentage than any other cause'","passage":"D","section":"독해"},{"q":"\"The two-in, two-out rule requires that whenever two firefighters enter an IDLH atmosphere, at least two must remain outside in a rescue-ready standby position.\"\n\nQ: 2인 진입·2인 대기 규정의 목적은?","opts":["물 절약","내부 대원 구조 보장","장비 보호","통신 유지"],"ans":1,"exp":"'remain outside in a rescue-ready standby position'","passage":"D","section":"독해"},{"q":"\"High-rise firefighting presents unique challenges: elevator control, stairwell pressurization, and managing civilian evacuation simultaneously with fire attack. Commanders must coordinate multiple objectives at once.\"\n\nQ: 고층 건물 화재의 특수 과제가 아닌 것은?","opts":["엘리베이터 통제","계단 가압","옥외 급수","민간인 대피 관리"],"ans":2,"exp":"옥외 급수(outdoor water supply)는 고층 건물 특수 과제로 언급되지 않음","passage":"E","section":"독해"},{"q":"\"Stairwell pressurization systems push fresh air into stairwells to prevent smoke infiltration, maintaining a safe evacuation route for occupants and a clear access path for firefighters.\"\n\nQ: 계단 가압 시스템의 목적은?","opts":["화재 진압","연기 침투 방지 및 안전 대피로 유지","물 공급","통신 강화"],"ans":1,"exp":"'prevent smoke infiltration, maintaining a safe evacuation route'","passage":"E","section":"독해"},{"q":"Q: 지문에서 'infiltration'의 의미는?","opts":["explosion","entry by penetration","removal","dispersion"],"ans":1,"exp":"infiltration = 침투, 스며듦","passage":"E","section":"독해"},{"q":"\"Responders must identify hazardous substances before committing resources. The ERG (Emergency Response Guidebook) provides initial action guides for over 3,000 materials, organized by UN identification number.\"\n\nQ: ERG의 주요 용도는?","opts":["물질 생산 지침","위험 물질 초기 대응 안내","화재 진압 절차","인원 배치 계획"],"ans":1,"exp":"'provides initial action guides for over 3,000 materials'","passage":"F","section":"독해"},{"q":"Q: 지문에서 'committing'의 의미는?","opts":["documenting","deploying/assigning","withdrawing","assessing"],"ans":1,"exp":"committing resources = 자원을 투입하다(deploying)","passage":"F","section":"독해"},{"q":"\"Hazardous materials incidents require three zones: hot zone (only fully protected personnel), warm zone (decontamination corridor), and cold zone (command and staging). Access is strictly controlled to prevent contamination spread.\"\n\nQ: 핫존(hot zone)에 진입할 수 있는 사람은?","opts":["모든 응급요원","완전 보호 장비 착용자만","의료 지원팀","감독관"],"ans":1,"exp":"'hot zone — only fully protected personnel'","passage":"F","section":"독해"},{"q":"\"Thermal imaging cameras allow firefighters to detect heat signatures through smoke and darkness. However, they require regular calibration and battery maintenance to ensure accuracy.\"\n\nQ: 열화상 카메라의 유지관리 요건은?","opts":["일회성 구매","정기 교정 및 배터리 관리","전문가 전용 사용","연간 교체"],"ans":1,"exp":"'require regular calibration and battery maintenance'","passage":"G","section":"독해"},{"q":"\"Predictive fire modeling uses weather data, topography, and fuel load information to forecast fire spread. This allows commanders to pre-position resources strategically rather than reacting after the fact.\"\n\nQ: 예측 화재 모델링의 전술적 이점은?","opts":["화재 원인 조사","선제적 자원 배치","보험 청구 지원","언론 브리핑 준비"],"ans":1,"exp":"'pre-position resources strategically rather than reacting'","passage":"G","section":"독해"},{"q":"\"The use of drones in firefighting has expanded rapidly. Departments deploy UAVs to conduct reconnaissance, map fire perimeters, and assess structural damage from a safe distance, reducing unnecessary risk to personnel.\"\n\nQ: 소방에서 드론 사용의 주요 이점은?","opts":["화재 직접 진압","안전 거리에서 정찰·피해 평가","통신 중계","물 공급 보조"],"ans":1,"exp":"'conduct reconnaissance, map perimeters, assess damage from safe distance'","passage":"G","section":"독해"},{"q":"\"The transition from offensive to defensive operations is critical. Commanders must continuously reassess structural conditions and withdraw interior crews when the risk-benefit ratio shifts unfavorably.\"\n\nQ: 공세에서 수세 전술로 전환을 결정하는 기준은?","opts":["시간 경과","위험-이익 비율","물 공급량","인원 수"],"ans":1,"exp":"'when the risk-benefit ratio shifts unfavorably'","passage":"H","section":"독해"},{"q":"\"Rapid intervention teams (RIT) must be designated and in place before interior operations begin. Their sole mission is to rescue firefighters in distress, and they must not be diverted to other tasks.\"\n\nQ: RIT의 임무가 아닌 것은?","opts":["위기 소방관 구조","내부 진입 대기","민간인 대피 지원","구조 준비 유지"],"ans":2,"exp":"'sole mission is to rescue firefighters in distress ... must not be diverted'","passage":"H","section":"독해"},{"q":"Q: 지문에서 'diverted'의 의미는?","opts":["trained","redirected","deployed","activated"],"ans":1,"exp":"diverted = 전용되다, 다른 곳으로 돌려지다(redirected)","passage":"H","section":"독해"},{"q":"\"Class A foam reduces water's surface tension, allowing deeper penetration into solid fuels. This improves extinguishing efficiency and reduces water consumption compared to plain water attacks.\"\n\nQ: Class A 폼의 작용 원리는?","opts":["화재를 냉각시킴","표면 장력 감소로 연료 깊숙이 침투","산소 차단","화학 반응 억제"],"ans":1,"exp":"'reduces surface tension, allowing deeper penetration into solid fuels'","passage":"I","section":"독해"},{"q":"\"Relay pumping extends water supply reach by connecting multiple pumpers in series. Each pumper receives water from the one behind and boosts pressure to the next, enabling operations far from a water source.\"\n\nQ: 릴레이 펌핑의 목적은?","opts":["물 절약","원거리 급수 가능","호스 보호","압력 감소"],"ans":1,"exp":"'enabling operations far from a water source'","passage":"I","section":"독해"},{"q":"\"Primary search is conducted rapidly after fire attack begins, covering the most likely survival areas first. Secondary search is a thorough, systematic search of the entire structure after the fire is controlled.\"\n\nQ: 1차 수색과 2차 수색의 차이는?","opts":["수색 팀 수","빠른 주요 지역 vs 통제 후 체계적 전체 수색","밤낮 구분","장비 종류"],"ans":1,"exp":"'rapidly ... most likely survival areas' vs 'thorough, systematic ... after fire controlled'","passage":"J","section":"독해"},{"q":"\"Search and rescue in confined spaces requires atmospheric testing for oxygen, flammable gases, and toxic substances before entry. Entry without testing is a leading cause of responder fatalities.\"\n\nQ: 밀폐 공간 진입 전 반드시 해야 할 것은?","opts":["현장 사진 촬영","산소·가스·독성 물질 대기 측정","안전 브리핑 실시","경계선 설치"],"ans":1,"exp":"'atmospheric testing for oxygen, flammable gases, and toxic substances before entry'","passage":"J","section":"독해"}]];
